/**
 * Adaptation of {@code NodeWrappersTestsContributor} tp JUnit5 API.
 */
public class JUnit5InprocessTestsContributor extends AbstractInProcessTestMixin implements JUnit5TestContributor {
  private static final Logger LOG = Logger.getLogger(JUnit5InprocessTestsContributor.class);

  private final Environment myEnv = new InProcessEnvironment();

  public JUnit5InprocessTestsContributor(MPSProject mpsProject, String runConfigurationName, Iterable<? extends ITestNodeWrapper> testNodes) {
    super(mpsProject, runConfigurationName, testNodes);

  }

  @Override
  protected void executeSafe() throws Throwable {
    initExtensions();
    executeWithJUnit5(collectSelectors(), collectTestEngines());
  }

  public void initExtensions() {
    EnvironmentAwareExtension.setEnvironment(myEnv);
  }

  protected void executeWithJUnit5(List<DiscoverySelector> selectors, List<TestEngine> engines) {
    LauncherDiscoveryRequest request = LauncherDiscoveryRequestBuilder.request().selectors(selectors).configurationParameter("junit.platform.output.capture.stdout", "true").configurationParameter("junit.platform.output.capture.stderr", "true").build();

    LauncherConfig.Builder builder = LauncherConfig.builder().enableTestEngineAutoRegistration(false).enablePostDiscoveryFilterAutoRegistration(false).enableLauncherSessionListenerAutoRegistration(false).enableLauncherDiscoveryListenerAutoRegistration(false).enableTestExecutionListenerAutoRegistration(false);
    builder.addTestEngines(engines.toArray(new TestEngine[engines.size()]));

    LauncherConfig launcherConfig = builder.build();
    Launcher launcher = LauncherFactory.openSession(launcherConfig).getLauncher();
    DefaultTestExecutionListener listener = new DefaultTestExecutionListener(myOutStream);
    try {
      launcher.execute(request, listener);

    } finally {
      this.myFailureCount = listener.getFailuresCount();
    }
  }


  @Override
  public List<DiscoverySelector> collectSelectors() {
    return new ModelAccessHelper(myProject.getModelAccess()).runReadAction(() -> {
      final List<DiscoverySelector> selectorsList = new ArrayList<DiscoverySelector>();
      InProcessExecutionFilter filter = new InProcessExecutionFilter();
      for (ITestNodeWrapper testNode : myTestNodes) {
        String fqName = testNode.getFqName();
        final SModule testModule = testNode.getTestNodeModule().resolve(myProject.getRepository());
        SNode testNodeSrc = testNode.getNodePointer().resolve(myProject.getRepository());
        SModel testModel = (testNodeSrc == null ? null : testNodeSrc.getModel());
        if (testNode.isTestCase()) {
          selectorsList.add(processTestCase(filter, testNode, testModule, testModel, fqName));
        } else {
          selectorsList.add(processTestMethod(filter, testNode, testModule, testModel, fqName));
        }
      }
      return selectorsList;
    });
  }

  @Override
  public List<TestEngine> collectTestEngines() {
    final SRepository repo = myEnv.getPlatform().findComponent(MPSModuleRepository.class);
    return new ModelAccessHelper(repo).runReadAction(() -> {
      final ArrayList<TestEngine> engines = new ArrayList<>();
      for (TestEngineDescriptor ted : ListSequence.fromList(TestPlatform.getInstance().getTestEngineDescriptors())) {
        ClassLoader classLoader = ted.getClass().getClassLoader();
        SModuleReference moduleReference = ModuleReference.parseReference(JUnitPlatform.JUNIT5_LIBS_MODULE_REF);
        SModule module = null;
        if (classLoader instanceof ModuleClassLoader) {
          module = ((ModuleClassLoader) classLoader).getModule();
        }
        if (module == null) {
          module = moduleReference.resolve(repo);
        }
        if (module instanceof ReloadableModule) {
          String className = ted.testEngineClassName();
          try {
            Class<?> cls = ((ReloadableModule) module).getClass(className);
            Constructor<?> ctor = cls.getConstructor();
            Object obj = ctor.newInstance();
            TestEngine engine = TestEngine.class.cast(obj);
            engines.add(engine);

          } catch (ClassNotFoundException | NoSuchMethodException | InstantiationException | InvocationTargetException | IllegalAccessException ex) {
            if (LOG.isErrorLevel()) {
              LOG.error("error creating test engine", ex);
            }
          }
        } else {
          if (LOG.isErrorLevel()) {
            LOG.error("can't load classes from module " + module.getModuleReference());
          }
        }
      }
      return engines;
    });

  }

  @NotNull
  private DiscoverySelector processTestCase(InProcessExecutionFilter filter, ITestNodeWrapper testNode, SModule testModule, SModel testModel, String fqName) {
    try {
      filter.check(testNode, testModel);
      return selectorForTestClass(fqName, testModule);
    } catch (InProcessExecutionFilter.InProcessCheckException e) {
      notifyByBaloonCheckException(e, testNode);
      return createFailedSelectorForClass(fqName, e);
    } catch (ClassNotFoundException e) {
      notifyByBaloonCLNF(e, testNode);
      return createFailedSelectorForClass(fqName, e);
    } catch (Exception e) {
      return createFailedSelectorForClass(fqName, e);
    }
  }

  @NotNull
  private DiscoverySelector processTestMethod(InProcessExecutionFilter filter, ITestNodeWrapper testNode, SModule testModule, SModel testModel, String fqName) {
    int index = fqName.lastIndexOf('.');
    String testFqName = fqName.substring(0, index);
    String methodName = fqName.substring(index + 1);
    try {
      filter.check(testNode, testModel);
      return selectorForTestMethod(testFqName, methodName, testModule);

    } catch (InProcessExecutionFilter.InProcessCheckException e) {
      notifyByBaloonCheckException(e, testNode);
      return createFailedSelectorForMethod(testFqName, methodName, e);
    } catch (ClassNotFoundException e) {
      notifyByBaloonCLNF(e, testNode);
      return createFailedSelectorForMethod(testFqName, methodName, e);
    } catch (Exception e) {
      return createFailedSelectorForMethod(testFqName, methodName, e);
    }
  }


  private DiscoverySelector createFailedSelectorForClass(String fqName, Exception e) {
    // FIXME implement using special TestEngine
    throw new UnsupportedOperationException("not implemented");
  }

  private DiscoverySelector createFailedSelectorForMethod(String testFqName, String methodName, Exception e) {
    // FIXME implement using special TestEngine
    throw new UnsupportedOperationException("not implemented");
  }

  private DiscoverySelector selectorForTestMethod(String fqName, String methodName, SModule module) throws ClassNotFoundException, ModuleClassLoaderIsNullException {
    final Class<?> aClass = loadTestClass(fqName, module);
    return DiscoverySelectors.selectMethod(aClass, methodName);
  }

  private DiscoverySelector selectorForTestClass(String fqName, SModule module) throws ClassNotFoundException, ModuleClassLoaderIsNullException {
    final Class<?> aClass = loadTestClass(fqName, module);
    return DiscoverySelectors.selectClass(aClass);
  }


}
